            }
            prompt += "[INST] " + user_content + " [/INST]";
        } else if (role == "assistant") {
            prompt += " " + content + "</s>";
        }
    }

    data.prompt  = prompt;
    data.format  = COMMON_CHAT_FORMAT_CONTENT_ONLY;
    return data;
